local GUIDressContent = class("GUIDressContent", IGUILayout)

function GUIDressContent:onLoad()
    self.tvCurrencyTip = self:getChildWindow("DressContent-Currency-Tip", GUIType.StaticText)
    self.ivCurrencyIcon = self:getChildWindow("DressContent-Currency-Icon", GUIType.StaticImage)
    self.tvCurrencyNum = self:getChildWindow("DressContent-Currency-Num", GUIType.StaticText)
    self.tvContentText = self:getChildWindow("DressContent-Content-Text", GUIType.StaticText)
    self.tvCurrencyTip:SetVisible(false)
end

DressContent = buildCustomDialogContent(GUIDressContent, "DressContent.json")

function DressContent:setCurrencyInfo(icon, uiType, count)
    if uiType == 1 then
        self.ivCurrencyIcon:SetVisible(true)
        self.tvContentText:SetVerticalAlignment(VerticalAlignment.Center)
        self:setContentText(Lang:getString("gui_TowerDefenseDress-buydress"))
        self.ivCurrencyIcon:SetImage(icon)
        self.tvCurrencyNum:SetText(tostring(count))
    elseif uiType == 2 then
        self.ivCurrencyIcon:SetVisible(false)
        self.tvContentText:SetVerticalAlignment(VerticalAlignment.Top)
        self:setContentText(Lang:getString("gui_TowerDefenseDress-changedress"))
    elseif uiType == 3 then
        self.ivCurrencyIcon:SetVisible(false)
        self.tvContentText:SetVerticalAlignment(VerticalAlignment.Top)
        self:setContentText(Lang:getString("gui_TowerDefenseDress-havedress"))
    end
end

function DressContent:setContentText(text)
    self.tvContentText:SetText(Lang:getString(text))
end

function DressContent:setCurrencyTip(text)
    self.tvCurrencyTip:SetText(text)
end

function DressContent:setCurrencyNum(text)
    self.tvCurrencyNum:SetText(tostring(text))
end